arguments.new_str:
protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // Keep legacy discriminator property name so existing documents remain queryable.
    // EF Core 9 changed the default from "Discriminator" to "$type".
    modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

    // Keep legacy compound id format ("Blog|1") so existing documents are still found.
    // EF Core 9 changed the default to key-only ids.
    modelBuilder.Entity<Blog>().HasRootDiscriminatorInJsonId(true);

    // HasIndex removed â€” Cosmos DB provider now throws at startup.
    // Manage indexes via the container's indexing policy in Azure instead.
}

