arguments.new_str:
class SyncJob
{
    // Cosmos DB provider in EF Core 9 no longer supports sync I/O;
    // ToList() and SaveChanges() now throw. Use async equivalents.
    async Task RunAsync(BlogContext context)
    {
        var blogs = await context.Blogs.ToListAsync();
        foreach (var b in blogs) { b.Name = b.Name.Trim(); }
        await context.SaveChangesAsync();
    }
}

